from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    xlsx_files = list(Path(workspace_path).glob('*RA_Queue*'))
    if not xlsx_files:
        all_xlsx = list(Path(workspace_path).glob('*.xlsx'))
        xlsx_files = [f for f in all_xlsx if 'queue' in f.name.lower() or 'ra' in f.name.lower()]
    if not xlsx_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'No RA Queue xlsx file found in workspace'}

    wb = openpyxl.load_workbook(xlsx_files[0])
    ws = wb.active

    e2_val = str(ws['E2'].value or '').strip()
    e3_val = str(ws['E3'].value or '').strip()
    e4_val = str(ws['E4'].value or '').strip()

    issues = []
    found = []

    # E2 must be 'Level 4: Low' — both 'level 4' AND 'low' must be present
    if 'level 4' not in e2_val.lower() or 'low' not in e2_val.lower():
        issues.append(f'E2 expected "Level 4: Low" but got "{e2_val}"')
    else:
        found.append(f'E2="{e2_val}"')

    # E3 must be 'Level 2: High' — both 'level 2' AND 'high' must be present
    if 'level 2' not in e3_val.lower() or 'high' not in e3_val.lower():
        issues.append(f'E3 expected "Level 2: High" but got "{e3_val}"')
    else:
        found.append(f'E3="{e3_val}"')

    # E4 must be 'Level 2: High' — both 'level 2' AND 'high' must be present
    if 'level 2' not in e4_val.lower() or 'high' not in e4_val.lower():
        issues.append(f'E4 expected "Level 2: High" but got "{e4_val}"')
    else:
        found.append(f'E4="{e4_val}"')

    if issues:
        return {'pass': False, 'score': 0.0, 'feedback': '; '.join(issues) + f' in {xlsx_files[0].name}'}

    return {'pass': True, 'score': 1.0, 'feedback': ', '.join(found) + f' - all risk levels correctly set in {xlsx_files[0].name}'}

