from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    xlsx_files = list(Path(workspace_path).glob('*Denial_Worklist*'))
    if not xlsx_files:
        all_xlsx = list(Path(workspace_path).glob('*.xlsx'))
        xlsx_files = [f for f in all_xlsx if 'denial' in f.name.lower() or 'worklist' in f.name.lower()]
    if not xlsx_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'No Denial Worklist xlsx file found in workspace'}

    wb = openpyxl.load_workbook(xlsx_files[0])
    ws = wb.active

    expected = {
        'H2': 'written off',
        'I2': 'write off',
        'H3': 'escalated',
        'I3': 'appeal - contractual rate dispute',
        'H4': 'written off',
        'I4': 'write off'
    }

    issues = []
    found = {}
    for cell_ref, exp_val in expected.items():
        actual = str(ws[cell_ref].value or '').strip().lower()
        found[cell_ref] = actual
        if actual != exp_val:
            issues.append(f'{cell_ref} expected "{exp_val}" but got "{actual}"')

    if issues:
        return {'pass': False, 'score': 0.0, 'feedback': '; '.join(issues) + f' in {xlsx_files[0].name}'}

    return {'pass': True, 'score': 1.0, 'feedback': f'All Denial Worklist cells verified: {found} in {xlsx_files[0].name}'}

from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'external_services_path is None; cannot check Slack data'}

    slack_path = Path(external_services_path) / 'slack_data.json'
    if not slack_path.exists():
        return {'pass': False, 'score': 0.0, 'feedback': f'slack_data.json not found at {slack_path}'}

    with open(slack_path) as f:
        data = json.load(f)

    messages_by_channel = data.get('messages', {})
    channels = data.get('channels', {})

    name_to_id = {ch_data.get('name', '').lower(): ch_id for ch_id, ch_data in channels.items()}

    total_messages = sum(len(msgs) for msgs in messages_by_channel.values())
    all_messages = [
        (channels.get(ch_id, {}).get('name', ch_id), msg.get('text', ''))
        for ch_id, msgs in messages_by_channel.items()
        for msg in msgs
    ]

    def normalize(s):
        # strip square brackets so "[RCM Manager]" matches "RCM Manager"
        return s.replace('[', '').replace(']', '').strip().lower()

    issues = []

    if total_messages != 2:
        issues.append(f'Expected exactly 2 total Slack messages but found {total_messages}: {all_messages}')

    expected_escalation = 'RCM Manager - Claim ID: CLM-2026-0048; Reason: Payer Dispute; Escalation Category: Operational'
    escalations_id = name_to_id.get('escalations')
    escalations_msgs = messages_by_channel.get(escalations_id, []) if escalations_id else []
    if not escalations_msgs:
        for ch_id, msgs in messages_by_channel.items():
            if channels.get(ch_id, {}).get('name', '').lower() == 'escalations':
                escalations_msgs = msgs
                break

    escalation_found = any(
        normalize(msg.get('text', '')) == normalize(expected_escalation)
        for msg in escalations_msgs
    )
    if not escalation_found:
        issues.append(f'No #escalations message matching "{expected_escalation}" (brackets ignored). Found: {[m.get("text") for m in escalations_msgs]}')

    expected_special_auth = 'James W. - CLM-2026-0049 special action authorized'
    special_auth_id = name_to_id.get('special-authorization')
    special_auth_msgs = messages_by_channel.get(special_auth_id, []) if special_auth_id else []
    if not special_auth_msgs:
        for ch_id, msgs in messages_by_channel.items():
            if 'special' in channels.get(ch_id, {}).get('name', '').lower() and 'auth' in channels.get(ch_id, {}).get('name', '').lower():
                special_auth_msgs = msgs
                break

    special_found = any(
        normalize(msg.get('text', '')) == normalize(expected_special_auth)
        for msg in special_auth_msgs
    )
    if not special_found:
        issues.append(f'No #special-authorization message matching "{expected_special_auth}" (brackets ignored). Found: {[m.get("text") for m in special_auth_msgs]}')

    if issues:
        return {'pass': False, 'score': 0.0, 'feedback': '; '.join(issues)}

    return {'pass': True, 'score': 1.0, 'feedback': f'Slack verified: #escalations match for CLM-2026-0048/Operational; #special-authorization match for CLM-2026-0049; total messages=2'}

from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'external_services_path is None; cannot check calendar data'}

    cal_path = Path(external_services_path) / 'calendar_data.json'
    if not cal_path.exists():
        return {'pass': False, 'score': 0.0, 'feedback': f'calendar_data.json not found at {cal_path}'}

    with open(cal_path) as f:
        data = json.load(f)

    events_raw = data.get('events', {})
    if isinstance(events_raw, dict):
        events_list = list(events_raw.values())
        total_events = len(events_raw)
    elif isinstance(events_raw, list):
        events_list = events_raw
        total_events = len(events_raw)
    else:
        return {'pass': False, 'score': 0.0, 'feedback': f'Unexpected events format: {type(events_raw)}'}

    issues = []

    if total_events != 15:
        issues.append(f'Expected exactly 15 calendar events but found {total_events}')

    # Accept the summary with or without square brackets around each filled-in field.
    # \[?  means "an optional [ "  and  \]? means "an optional ] ".
    # \s* allows for any extra spaces.
    summary_pattern = re.compile(
        r'^\s*'
        r'\[?\s*RCM Manager\s*\]?'
        r'\s*-\s*Claim ID:\s*'
        r'\[?\s*CLM-2026-0048\s*\]?'
        r'\s*;\s*Reason:\s*'
        r'\[?\s*Payer Dispute\s*\]?'
        r'\s*;\s*Escalation Category:\s*'
        r'\[?\s*Operational\s*\]?'
        r'\s*$',
        re.IGNORECASE
    )

    target_event = None
    for event in events_list:
        summary = str(event.get('summary', '')).strip()
        if summary_pattern.match(summary):
            target_event = event
            break

    if target_event is None:
        all_summaries = [str(e.get('summary', '')) for e in events_list]
        issues.append(
            'No calendar event found with summary matching '
            '"RCM Manager - Claim ID: CLM-2026-0048; Reason: Payer Dispute; '
            'Escalation Category: Operational" (square brackets around field values are allowed). '
            f'Found summaries: {all_summaries}'
        )
    else:
        start = str(target_event.get('start', ''))
        end = str(target_event.get('end', ''))

        def check_datetime(dt_str, label):
            dt_lower = dt_str.lower().strip()
            local_issues = []

            date_found = False
            if '2026-02-16' in dt_str:
                date_found = True
            elif '02/16/2026' in dt_str:
                date_found = True
            elif '2/16/2026' in dt_str:
                date_found = True
            elif 'feb' in dt_lower and '16' in dt_str and '2026' in dt_str:
                date_found = True
            elif '2026' in dt_str and '02' in dt_str and '16' in dt_str:
                date_found = True

            if not date_found:
                local_issues.append(f'{label} "{dt_str}" does not clearly indicate February 16, 2026')

            time_found = False
            if '15:15' in dt_str:
                time_found = True
            elif '3:15 pm' in dt_lower:
                time_found = True
            elif '3:15pm' in dt_lower:
                time_found = True
            elif re.search(r'3:15\s*[pP]', dt_str):
                time_found = True

            if not time_found:
                local_issues.append(f'{label} "{dt_str}" does not clearly indicate 3:15 PM')

            return local_issues

        issues.extend(check_datetime(start, 'Event start time'))
        issues.extend(check_datetime(end, 'Event end time'))

    if issues:
        return {'pass': False, 'score': 0.0, 'feedback': '; '.join(issues)}

    return {'pass': True, 'score': 1.0, 'feedback': f'Calendar verified: {total_events} events found; escalation event found with valid summary, start and end at 3:15 PM Feb 16 2026'}

from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'external_services_path is None; cannot check mailbox data'}

    mailbox_path = Path(external_services_path) / 'mailbox.json'
    if not mailbox_path.exists():
        # If no mailbox file exists, there are no sent emails - pass
        return {'pass': True, 'score': 1.0, 'feedback': 'No mailbox.json found; no sent emails exist'}

    with open(mailbox_path) as f:
        data = json.load(f)

    emails = data.get('emails', [])
    sent_emails = [e for e in emails if str(e.get('folder', '')).lower() == 'sent']

    if sent_emails:
        subjects = [e.get('subject', 'no subject') for e in sent_emails]
        return {'pass': False, 'score': 0.0, 'feedback': f'Found {len(sent_emails)} sent email(s) but expected none. Subjects: {subjects}'}

    return {'pass': True, 'score': 1.0, 'feedback': f'No sent emails found in mailbox. Total emails: {len(emails)}'}
